test('navigates to accessibility page and verifies title', async ({ page }) => {
  await page.goto('https://agency.example.org/accessibility');
  await page.waitForLoadState('domcontentloaded');

  await expect(page).toHaveTitle(/Accessibility Statement/);
});
```

