```typescript
import { test as baseTest, expect } from '@playwright/test';

interface TestFixtures {
  authenticatedPage: Page;
}

const test = baseTest.extend<TestFixtures>({
  authenticatedPage: async ({ browser }, use) => {
    const context = await browser.newContext();
    const page = await context.newPage();

    await page.goto('https://agency.example.org/login');
    await page.getByLabel('Username').fill('testuser');
    await page.getByLabel('Password').fill('SecurePass123!');
    await page.getByRole('button', { name: 'Sign In' }).click();
    await page.waitForLoadState('networkidle');

    // Save session state for reuse
    await context.storageState({ path: 'state.json' });

    // Create new context with stored state for subsequent tests
    const reusableContext = await browser.newContext({
      storageState: 'state.json'
    });
    const reusablePage = await reusableContext.newPage();

    await use(reusablePage);

    await reusableContext.close();
    await context.close();
  }
});

// Usage in tests

test('loads dashboard with accessible elements', async ({ authenticatedPage }) => {
  await authenticatedPage.goto('https://agency.example.org/dashboard');
  await expect(authenticatedPage.getByRole('heading', { name: 'Dashboard' })).toBeVisible();
});
```

Use role-based locators combined with filtering by descendant text—this is resilient to DOM changes and aligns with how users perceive the interface:

```typescript
import { test, expect } from '@playwright/test';

test('edits Maria Chen’s record', async ({ page }) => {
  await page.goto('https://agency.example.org/users');

  // Locate the row (listitem) that contains a heading with Maria Chen’s name,
  // then click its Edit button
  const mariaRow = page.getByRole('row').filter({
    has: page.getByRole('rowheader').filter({ hasText: 'Maria Chen' })
  });

  await mariaRow.getByRole('button', { name: 'Edit' }).click();

  await expect(page).toHaveURL(/.*\/edit/);
});
```

Use `page.goto()`, `waitForLoadState()`, and `getByRole('button', { name: 'Subscribe' })` with a visibility/enabled check before clicking:

```typescript
import { test, expect } from '@playwright/test';

test('subscribe button becomes clickable after load', async ({ page }) => {
  await page.goto('https://agency.example.org/subscribe');
  await page.waitForLoadState('networkidle');

  const subscribeButton = page.getByRole('button', { name: 'Subscribe' });
  await expect(subscribeButton).toBeVisible();
  await expect(subscribeButton).toBeEnabled();

  await subscribeButton.click();
});
```

Key points:
- `networkidle` waits until there are no more than 0 network connections for at least 500 ms — ideal for dynamic content.
- `toBeVisible()` ensures the button is present and not hidden via CSS.
- `toBeEnabled()` ensures the button is not disabled (e.g., via `disabled` attribute).
- Using `getByRole('button', { name: 'Subscribe' })` is robust and accessible; it matches the button’s accessible name (not just inner text).

Use `.filter({ visible: true })` before interacting. Playwright’s strict mode throws when multiple elements match, so narrowing to visible elements is necessary:

```typescript
import { test, expect } from '@playwright/test';

test('clicks only the visible button', async ({ page }) => {
  await page.setContent(`
    <button style="display: none;">Invisible</button>
    <button>Visible</button>
  `);

  const buttons = page.locator('button');
  const visibleButton = buttons.filter({ visible: true });

  await expect(visibleButton).toHaveCount(1);
  await visibleButton.click();

  // Optional: assert the visible button is the expected one
  await expect(visibleButton).toHaveText('Visible');
});
```

Alternatively, if you know the accessible name, prefer a more resilient locator:

```ts
await page.getByRole('button', { name: 'Visible' }).click();
```

Best practice: Avoid relying on visibility filters; instead, use semantic attributes (e.g., `aria-hidden`, `disabled`, or test IDs) to ensure only intended elements match.

Use `toHaveCount()` and `toHaveText()` with an array to assert both count and ordered content:

```typescript
import { test, expect } from '@playwright/test';

test('list has 3 items in correct order', async ({ page }) => {
  await page.setContent(`
    <ul>
      <li>apple</li>
      <li>banana</li>
      <li>orange</li>
    </ul>
  `);

  const listItems = page.getByRole('listitem');

  // Assert exact count
  await expect(listItems).toHaveCount(3);

  // Assert exact text order (case-sensitive, trimmed)
  await expect(listItems).toHaveText(['apple', 'banana', 'orange']);
});
```

Notes:
- `toHaveText()` with an array checks both *presence*, *count*, and *order*.
- Use `page.getByRole('listitem')` instead of `locator('li')` to ensure semantic correctness (WCAG 1.3.1).
- If list items may have whitespace, normalize via `trim()` in test setup or use `textContent` with `evaluateAll()` for custom logic.

Use `page.goto()` with `waitUntil: 'networkidle'` and combine with `expect().toHaveURL()` or `waitForLoadState()` for robust navigation handling.

**Recommended pattern:**

```ts
import { test, expect } from '@playwright/test';

test('navigates and waits for content', async ({ page }) => {
  await page.goto('/dashboard', { waitUntil: 'networkidle' });

  // Wait for main content region to be visible
  await page.waitForSelector('main[role="main"]', { state: 'visible' });

  // Or use waitForLoadState for fine-grained control:
  await page.waitForLoadState('domcontentloaded');
  await page.waitForLoadState('networkidle');

  await expect(page).toHaveURL(/\/dashboard$/);
  await expect(page.getByRole('heading', { name: 'Dashboard' })).toBeVisible();
});
```

**Configuration tip:** In `playwright.config.ts`, set a reasonable `timeout` (e.g., 30000 ms) and `expect.timeout` (e.g., 5000 ms) to avoid flaky timing assumptions:

```ts
expect: {
  timeout: 5000
}
```

Avoid hardcoded `setTimeout()` — Playwright’s built-in waiting is more reliable.

Use Playwright’s **test fixtures** (`test.beforeEach`) combined with `test.use()` to inject authenticated state. Here’s a full example:

```ts
import { test, expect, Page } from '@playwright/test';

// Define a reusable fixture that logs in and stores auth context
const authedTest = test.extend<{ authenticatedPage: Page }>({
  authenticatedPage: async ({ browser }, use) => {
    const context = await browser.newContext();
    const page = await context.newPage();

    // Perform login (adjust URLs/inputs to your app)
    await page.goto('/login');
    await page.getByLabel('Email').fill('user@gov.example.org');
    await page.getByLabel('Password').fill('secure-password');
    await page.getByRole('button', { name: 'Log In' }).click();
    await page.waitForURL('/dashboard');

    await use(page);
    await context.close();
  }
});

// Use the fixture in tests
authedTest('shows dashboard after login', async ({ authenticatedPage }) => {
  await expect(authenticatedPage.getByRole('heading', { name: 'Welcome' })).toBeVisible();
});
```

**Alternative (faster for multiple tests): reuse auth context across tests**

```ts
test.describe.configure({ mode: 'serial' });

let context: BrowserContext;
let page: Page;

test.beforeAll(async ({ browser }) => {
  context = await browser.newContext();
  page = await context.newPage();
  // login logic...
});

test.afterAll(async () => {
  await context.close();
});

// Then use `page` fixture in tests
```

✅ Best practice: Prefer `test.use()` for isolation; reuse context only when performance is critical.

Configure global timeouts via `defineConfig()` in `playwright.config.ts`. Use `testTimeout` for full test duration and `expectTimeout` for `expect()` assertions (e.g., `expect(locator).toHaveText()`).

Default `expectTimeout` is **5 seconds**, while `testTimeout` defaults to **30 seconds**.

Example `playwright.config.ts`:
```ts
import { defineConfig } from '@playwright/test';

export default defineConfig({
  timeout: 30000, // testTimeout
  expect: {
    timeout: 5000, // expectTimeout
  },
  use: {
    actionTimeout: 0, // disables per-action timeout (let expect timeout govern)
  },
});
```

Best practice: Keep `expectTimeout` ≤ `testTimeout` to avoid overlapping timeouts. Use `expect(locator, { timeout: X }).toHaveText()` if override per-assertion is needed.

